Here's a visually stunning, self-contained HTML file demonstrating the Bellman-Ford algorithm with exceptional aesthetics:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Bellman-Ford Algorithm Visualization</title>
    <style>
        :root {
            --primary: #6c5ce7;
            --secondary: #a29bfe;
            --dark: #2d3436;
            --light: #f5f6fa;
            --accent: #fd79a8;
            --success: #00b894;
            --warning: #fdcb6e;
            --danger: #d63031;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }

        body {
            background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 2rem;
            color: var(--dark);
            overflow-x: hidden;
        }

        .header {
            text-align: center;
            margin-bottom: 2rem;
            opacity: 0;
            transform: translateY(-20px);
            animation: fadeIn 0.8s ease-out forwards;
        }

        @keyframes fadeIn {
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        h1 {
            font-size: 2.8rem;
            font-weight: 700;
            margin-bottom: 0.5rem;
            background: linear-gradient(90deg, var(--primary), var(--accent));
            -webkit-background-clip: text;
            background-clip: text;
            color: transparent;
            letter-spacing: -0.5px;
        }

        .subtitle {
            font-size: 1.1rem;
            color: var(--dark);
            opacity: 0.8;
            max-width: 600px;
            margin: 0 auto;
            line-height: 1.6;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            width: 100%;
            max-width: 1200px;
            gap: 2rem;
        }

        .graph-container {
            position: relative;
            width: 100%;
            height: 500px;
            background: white;
            border-radius: 16px;
            box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
            overflow: hidden;
            padding: 2rem;
            opacity: 0;
            transform: scale(0.95);
            animation: scaleIn 0.6s 0.3s ease-out forwards;
        }

        @keyframes scaleIn {
            to {
                opacity: 1;
                transform: scale(1);
            }
        }

        .node {
            position: absolute;
            width: 60px;
            height: 60px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
            font-size: 1.2rem;
            color: white;
            background: var(--primary);
            box-shadow: 0 10px 20px rgba(108, 92, 231, 0.3);
            z-index: 10;
            transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
            cursor: default;
        }

        .node.active {
            transform: scale(1.1);
            background: var(--accent);
            box-shadow: 0 15px 30px rgba(253, 121, 168, 0.4);
        }

        .node.start {
            background: var(--success);
            box-shadow: 0 15px 30px rgba(0, 184, 148, 0.4);
        }

        .node.negative {
            background: var(--danger);
            box-shadow: 0 15px 30px rgba(214, 48, 49, 0.4);
        }

        .edge {
            position: absolute;
            height: 3px;
            background: var(--secondary);
            transform-origin: left center;
            z-index: 5;
            pointer-events: none;
        }

        .edge.active {
            background: var(--accent);
            height: 4px;
        }

        .edge.negative {
            background: var(--danger);
        }

        .weight {
            position: absolute;
            background: white;
            padding: 0.2rem 0.5rem;
            border-radius: 20px;
            font-size: 0.8rem;
            font-weight: bold;
            color: var(--primary);
            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.1);
            z-index: 15;
        }

        .weight.negative {
            color: var(--danger);
        }

        .controls {
            display: flex;
            gap: 1rem;
            margin-top: 1rem;
            opacity: 0;
            animation: fadeIn 0.6s 0.6s ease-out forwards;
        }

        button {
            padding: 0.8rem 1.8rem;
            border: none;
            border-radius: 50px;
            background: var(--primary);
            color: white;
            font-weight: 600;
            font-size: 1rem;
            cursor: pointer;
            transition: all 0.3s ease;
            box-shadow: 0 10px 20px rgba(108, 92, 231, 0.3);
        }

        button:hover {
            transform: translateY(-2px);
            box-shadow: 0 15px 30px rgba(108, 92, 231, 0.4);
        }

        button:active {
            transform: translateY(0);
        }

        button.secondary {
            background: white;
            color: var(--primary);
            border: 2px solid var(--primary);
        }

        .info-panel {
            width: 100%;
            background: white;
            border-radius: 16px;
            padding: 2rem;
            box-shadow: 0 20px 40px rgba(0, 0, 0, 0.08);
            margin-top: 2rem;
            opacity: 0;
            transform: translateY(20px);
            animation: fadeInUp 0.6s 0.9s ease-out forwards;
        }

        @keyframes fadeInUp {
            to {
                opacity: 1;
                transform: translateY(0);
            }
        }

        .info-panel h2 {
            font-size: 1.5rem;
            margin-bottom: 1rem;
            color: var(--primary);
        }

        .info-panel p {
            margin-bottom: 1rem;
            line-height: 1.6;
            color: var(--dark);
            opacity: 0.9;
        }

        .algorithm-steps {
            display: flex;
            flex-direction: column;
            gap: 1rem;
            margin-top: 1.5rem;
        }

        .step {
            display: flex;
            align-items: flex-start;
            gap: 1rem;
            padding: 1rem;
            border-radius: 8px;
            background: rgba(108, 92, 231, 0.05);
            transition: all 0.3s ease;
        }

        .step.active {
            background: rgba(108, 92, 231, 0.15);
            border-left: 4px solid var(--primary);
        }

        .step-number {
            background: var(--primary);
            color: white;
            width: 28px;
            height: 28px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
            font-size: 0.9rem;
            flex-shrink: 0;
        }

        .step-content {
            flex: 1;
        }

        .distance-table {
            width: 100%;
            border-collapse: collapse;
            margin-top: 1.5rem;
            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.05);
            border-radius: 8px;
            overflow: hidden;
        }

        .distance-table th, .distance-table td {
            padding: 0.8rem 1rem;
            text-align: center;
        }

        .distance-table th {
            background: var(--primary);
            color: white;
            font-weight: 600;
        }

        .distance-table tr:nth-child(even) {
            background: rgba(108, 92, 231, 0.05);
        }

        .distance-table tr:hover {
            background: rgba(108, 92, 231, 0.1);
        }

        .distance-table .updated {
            background: rgba(253, 121, 168, 0.2);
            font-weight: bold;
        }

        .distance-table .negative-cycle {
            background: rgba(214, 48, 49, 0.2);
            color: var(--danger);
            font-weight: bold;
        }

        .footer {
            margin-top: 3rem;
            text-align: center;
            font-size: 0.9rem;
            color: var(--dark);
            opacity: 0.6;
            animation: fadeIn 1s 1.2s ease-out forwards;
        }

        @media (max-width: 768px) {
            h1 {
                font-size: 2rem;
            }

            .graph-container {
                height: 400px;
            }
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>Bellman-Ford Algorithm</h1>
        <p class="subtitle">A beautiful visualization of the algorithm that finds shortest paths from a single source vertex to all other vertices in a weighted digraph, even with negative edge weights.</p>
    </div>

    <div class="container">
        <div class="graph-container" id="graph">
            <!-- Nodes and edges will be added dynamically -->
        </div>

        <div class="controls">
            <button id="startBtn">Start Visualization</button>
            <button class="secondary" id="resetBtn">Reset</button>
        </div>

        <div class="info-panel">
            <h2>Algorithm Overview</h2>
            <p>The Bellman-Ford algorithm is a graph search algorithm that finds the shortest paths from a single source vertex to all other vertices in a weighted digraph. Unlike Dijkstra's algorithm, it can handle graphs with negative edge weights and can detect negative cycles.</p>

            <div class="algorithm-steps">
                <div class="step">
                    <div class="step-number">1</div>
                    <div class="step-content">Initialize distances from the source to all vertices as infinite and to the source itself as 0.</div>
                </div>
                <div class="step">
                    <div class="step-number">2</div>
                    <div class="step-content">Relax all edges |V| - 1 times where |V| is the number of vertices in the graph.</div>
                </div>
                <div class="step">
                    <div class="step-number">3</div>
                    <div class="step-content">Check for negative weight cycles. If we can still relax any edge, then a negative cycle exists.</div>
                </div>
            </div>

            <table class="distance-table">
                <thead>
                    <tr>
                        <th>Vertex</th>
                        <th>Distance</th>
                        <th>Previous</th>
                    </tr>
                </thead>
                <tbody id="distanceTable">
                    <!-- Will be populated by JavaScript -->
                </tbody>
            </table>
        </div>
    </div>

    <div class="footer">
        <p>Bellman-Ford Algorithm Visualization | Designed for aesthetic excellence</p>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            // Graph configuration
            const graph = {
                nodes: [
                    { id: 'A', x: 150, y: 150 },
                    { id: 'B', x: 400, y: 100 },
                    { id: 'C', x: 400, y: 300 },
                    { id: 'D', x: 650, y: 150 },
                    { id: 'E', x: 650, y: 350 }
                ],
                edges: [
                    { from: 'A', to: 'B', weight: 4 },
                    { from: 'A', to: 'C', weight: 2 },
                    { from: 'B', to: 'C', weight: 3 },
                    { from: 'B', to: 'D', weight: 2 },
                    { from: 'B', to: 'E', weight: 3 },
                    { from: 'C', to: 'B', weight: 1 },
                    { from: 'C', to: 'D', weight: 4 },
                    { from: 'C', to: 'E', weight: 5 },
                    { from: 'D', to: 'E', weight: -3 } // Negative edge to demonstrate Bellman-Ford's capability
                ]
            };

            // Initialize distances and previous nodes
            let distances = {};
            let previous = {};
            let animationQueue = [];
            let isAnimating = false;
            let currentStep = 0;

            // DOM elements
            const graphContainer = document.getElementById('graph');
            const startBtn = document.getElementById('startBtn');
            const resetBtn = document.getElementById('resetBtn');
            const distanceTable = document.getElementById('distanceTable');

            // Initialize the graph visualization
            function initGraph() {
                // Clear the graph container
                graphContainer.innerHTML = '';

                // Create nodes
                graph.nodes.forEach(node => {
                    const nodeElement = document.createElement('div');
                    nodeElement.className = 'node';
                    nodeElement.id = `node-${node.id}`;
                    nodeElement.textContent = node.id;
                    nodeElement.style.left = `${node.x}px`;
                    nodeElement.style.top = `${node.y}px`;

                    if (node.id === 'A') {
                        nodeElement.classList.add('start');
                    }

                    graphContainer.appendChild(nodeElement);
                });

                // Create edges
                graph.edges.forEach(edge => {
                    const fromNode = graph.nodes.find(n => n.id === edge.from);
                    const toNode = graph.nodes.find(n => n.id === edge.to);

                    if (fromNode && toNode) {
                        // Calculate edge position and angle
                        const dx = toNode.x - fromNode.x;
                        const dy = toNode.y - fromNode.y;
                        const length = Math.sqrt(dx * dx + dy * dy);
                        const angle = Math.atan2(dy, dx) * 180 / Math.PI;

                        // Create edge element
                        const edgeElement = document.createElement('div');
                        edgeElement.className = 'edge';
                        if (edge.weight < 0) {
                            edgeElement.classList.add('negative');
                        }
                        edgeElement.style.width = `${length}px`;
                        edgeElement.style.left = `${fromNode.x + 30}px`;
                        edgeElement.style.top = `${fromNode.y + 30}px`;
                        edgeElement.style.transform = `rotate(${angle}deg)`;
                        edgeElement.id = `edge-${edge.from}-${edge.to}`;
                        graphContainer.appendChild(edgeElement);

                        // Create weight label
                        const weightElement = document.createElement('div');
                        weightElement.className = 'weight';
                        if (edge.weight < 0) {
                            weightElement.classList.add('negative');
                        }
                        weightElement.textContent = edge.weight;
                        weightElement.style.left = `${fromNode.x + dx/2 + 15}px`;
                        weightElement.style.top = `${fromNode.y + dy/2 + 15}px`;
                        weightElement.id = `weight-${edge.from}-${edge.to}`;
                        graphContainer.appendChild(weightElement);
                    }
                });
            }

            // Initialize distance table
            function initDistanceTable() {
                distanceTable.innerHTML = '';

                graph.nodes.forEach(node => {
                    const row = document.createElement('tr');
                    row.id = `row-${node.id}`;

                    const cellId = document.createElement('td');
                    cellId.textContent = node.id;

                    const cellDist = document.createElement('td');
                    cellDist.id = `dist-${node.id}`;
                    cellDist.textContent = node.id === 'A' ? '0' : '∞';

                    const cellPrev = document.createElement('td');
                    cellPrev.id = `prev-${node.id}`;
                    cellPrev.textContent = '-';

                    row.appendChild(cellId);
                    row.appendChild(cellDist);
                    row.appendChild(cellPrev);

                    distanceTable.appendChild(row);
                });
            }

            // Initialize algorithm state
            function initAlgorithm() {
                distances = {};
                previous = {};
                animationQueue = [];
                isAnimating = false;
                currentStep = 0;

                graph.nodes.forEach(node => {
                    distances[node.id] = node.id === 'A' ? 0 : Infinity;
                    previous[node.id] = null;
                });

                // Reset all visual elements
                document.querySelectorAll('.node').forEach(node => {
                    node.classList.remove('active', 'negative');
                    if (node.id === 'node-A') {
                        node.classList.add('start');
                    }
                });

                document.querySelectorAll('.edge').forEach(edge => {
                    edge.classList.remove('active');
                });

                document.querySelectorAll('.step').forEach((step, index) => {
                    step.classList.remove('active');
                    if (index === 0) {
                        step.classList.add('active');
                    }
                });
            }

            // Animate the Bellman-Ford algorithm
            function animateBellmanFord() {
                if (isAnimating) return;
                isAnimating = true;

                // Clear any existing animations
                animationQueue = [];

                // Generate animation steps
                const numVertices = graph.nodes.length;

                // Initialization step
                animationQueue.push({
                    action: 'highlight',
                    element: 'node-A',
                    callback: () => {
                        document.querySelector('.step:nth-child(
